+/**
+ * Multi-Model Router
+ *
+ * Cost-optimized routing across multiple LLM providers from agentic-flow@alpha:
+ * - anthropic: Claude models
+ * - openai: GPT models
+ * - openrouter: 100+ models, 85-99% cost savings
+ * - ollama: Local models
+ * - litellm: Unified API
+ * - onnx: Free local inference (Phi-4)
+ * - gemini: Google Gemini
+ * - custom: Custom providers
+ *
+ * Routing Modes:
+ * - manual: Explicit provider selection
+ * - cost-optimized: Minimize cost
+ * - performance-optimized: Minimize latency
+ * - quality-optimized: Maximize quality
+ * - rule-based: Custom routing rules
+ *
+ * Features:
+ * - Circuit breaker for reliability
+ * - Cost tracking with budget alerts
+ * - Tool calling translation
+ * - Streaming support
+ * - Response caching
+ *
+ * @module v3/integration/multi-model-router
+ */
+
+import { EventEmitter } from 'events';
+
+// =============================================================================
+// Types & Interfaces
+// =============================================================================
+
+/**
+ * Supported providers
+ */
+export type ProviderType =
+  | 'anthropic'   // Claude models
+  | 'openai'      // GPT models
+  | 'openrouter'  // 100+ models, 85-99% cost savings
+  | 'ollama'      // Local models
+  | 'litellm'     // Unified API
+  | 'onnx'        // Free local inference
+  | 'gemini'      // Google Gemini
+  | 'custom';     // Custom providers
+
+/**
+ * Routing mode
+ */
+export type RoutingMode =
+  | 'manual'               // Explicit provider selection
+  | 'cost-optimized'       // Minimize cost
+  | 'performance-optimized' // Minimize latency
+  | 'quality-optimized'    // Maximize quality
+  | 'rule-based';          // Custom routing rules
+
+/**
+ * Model capabilities
+ */
+export interface ModelCapabilities {
+  contextWindow: number;
+  supportsStreaming: boolean;
+  supportsTools: boolean;
+  supportsVision: boolean;
+  supportsJson: boolean;
+  maxOutputTokens: number;
+}
+
+/**
+ * Provider configuration
+ */
+export interface ProviderConfig {
+  type: ProviderType;
+  enabled: boolean;
+  apiKey?: string;
+  baseUrl?: string;
+  models: ModelConfig[];
+  defaultModel?: string;
+  timeout?: number;
+  retries?: number;
+}
+
+/**
+ * Model configuration
+ */
+export interface ModelConfig {
+  id: string;
+  name: string;
+  provider: ProviderType;
+  costPer1kInputTokens: number;
+  costPer1kOutputTokens: number;
+  latencyMs: number;
+  qualityScore: number; // 0-1
+  capabilities: ModelCapabilities;
+  aliases?: string[];
+}
+
+/**
+ * Routing request
+ */
+export interface RoutingRequest {
+  task: string;
+  messages: ChatMessage[];
+  requiredCapabilities?: Partial<ModelCapabilities>;
+  maxCost?: number;
+  maxLatency?: number;
+  minQuality?: number;
+  preferredProvider?: ProviderType;
+  preferredModel?: string;
+}
+
+/**
+ * Chat message
+ */
+export interface ChatMessage {
+  role: 'system' | 'user' | 'assistant' | 'tool';
+  content: string;
+  name?: string;
+  toolCalls?: ToolCall[];
+  toolCallId?: string;
+}
+
+/**
+ * Tool call
+ */
+export interface ToolCall {
+  id: string;
+  type: 'function';
+  function: {
+    name: string;
+    arguments: string;
+  };
+}
+
+/**
+ * Routing result
+ */
+export interface RoutingResult {
+  provider: ProviderType;
+  model: string;
+  reason: string;
+  estimatedCost: number;
+  estimatedLatency: number;
+  qualityScore: number;
+  alternatives?: Array<{
+    provider: ProviderType;
+    model: string;
+    estimatedCost: number;
+  }>;
+}
+
+/**
+ * Completion request
+ */
+export interface CompletionRequest {
+  messages: ChatMessage[];
+  model?: string;
+  provider?: ProviderType;
+  temperature?: number;
+  maxTokens?: number;
+  stream?: boolean;
+  tools?: Tool[];
+  responseFormat?: 'text' | 'json';
+}
+
+/**
+ * Tool definition
+ */
+export interface Tool {
+  type: 'function';
+  function: {
+    name: string;
+    description: string;
+    parameters: Record<string, unknown>;
+  };
+}
+
+/**
+ * Completion response
+ */
+export interface CompletionResponse {
+  id: string;
+  provider: ProviderType;
+  model: string;
+  content: string;
+  finishReason: 'stop' | 'length' | 'tool_calls';
+  toolCalls?: ToolCall[];
+  usage: {
+    inputTokens: number;
+    outputTokens: number;
+    totalTokens: number;
+  };
+  cost: number;
+  latency: number;
+}
+
+/**
+ * Router configuration
+ */
+export interface RouterConfig {
+  mode: RoutingMode;
+  providers: ProviderConfig[];
+  budgetLimit?: number;
+  budgetPeriod?: 'hourly' | 'daily' | 'monthly';
+  cacheTTL?: number;
+  circuitBreaker: {
+    enabled: boolean;
+    failureThreshold: number;
+    resetTimeout: number;
+  };
+  routing: {
+    preferLocalModels?: boolean;
+    costWeight?: number;
+    latencyWeight?: number;
+    qualityWeight?: number;
+  };
+  rules?: RoutingRule[];
+}
+
+/**
+ * Routing rule for rule-based mode
+ */
+export interface RoutingRule {
+  name: string;
+  condition: {
+    taskPattern?: RegExp | string;
+    minTokens?: number;
+    maxTokens?: number;
+    requiresTools?: boolean;
+    requiresVision?: boolean;
+  };
+  action: {
+    provider: ProviderType;
+    model?: string;
+    priority?: number;
+  };
+}
+
+/**
+ * Provider health status
+ */
+export interface ProviderHealth {
+  provider: ProviderType;
+  status: 'healthy' | 'degraded' | 'unhealthy';
+  lastError?: string;
+  failureCount: number;
+  successRate: number;
+  avgLatency: number;
+  circuitOpen: boolean;
+}
+
+/**
+ * Cost tracking
+ */
+export interface CostTracker {
+  periodStart: Date;
+  periodEnd: Date;
+  totalCost: number;
+  byProvider: Record<ProviderType, number>;
+  byModel: Record<string, number>;
+  requests: number;
+  tokensUsed: {
+    input: number;
+    output: number;
+  };
+}
+
+// =============================================================================
+// Default Models Configuration
+// =============================================================================
+
+const DEFAULT_MODELS: ModelConfig[] = [
+  // Anthropic
+  {
+    id: 'claude-3-5-sonnet-20241022',
+    name: 'Claude 3.5 Sonnet',
+    provider: 'anthropic',
+    costPer1kInputTokens: 0.003,
+    costPer1kOutputTokens: 0.015,
+    latencyMs: 500,
+    qualityScore: 0.95,
+    capabilities: {
+      contextWindow: 200000,
+      supportsStreaming: true,
+      supportsTools: true,
+      supportsVision: true,
+      supportsJson: true,
+      maxOutputTokens: 8192,
+    },
+  },
+  {
+    id: 'claude-3-opus-20240229',
+    name: 'Claude 3 Opus',
+    provider: 'anthropic',
+    costPer1kInputTokens: 0.015,
+    costPer1kOutputTokens: 0.075,
+    latencyMs: 1000,
+    qualityScore: 0.98,
+    capabilities: {
+      contextWindow: 200000,
+      supportsStreaming: true,
+      supportsTools: true,
+      supportsVision: true,
+      supportsJson: true,
+      maxOutputTokens: 4096,
+    },
+  },
+  {
+    id: 'claude-3-haiku-20240307',
+    name: 'Claude 3 Haiku',
+    provider: 'anthropic',
+    costPer1kInputTokens: 0.00025,
+    costPer1kOutputTokens: 0.00125,
+    latencyMs: 200,
+    qualityScore: 0.85,
+    capabilities: {
+      contextWindow: 200000,
+      supportsStreaming: true,
+      supportsTools: true,
+      supportsVision: true,
+      supportsJson: true,
+      maxOutputTokens: 4096,
+    },
+  },
+  // OpenAI
+  {
+    id: 'gpt-4-turbo',
+    name: 'GPT-4 Turbo',
+    provider: 'openai',
+    costPer1kInputTokens: 0.01,
+    costPer1kOutputTokens: 0.03,
+    latencyMs: 800,
+    qualityScore: 0.94,
+    capabilities: {
+      contextWindow: 128000,
+      supportsStreaming: true,
+      supportsTools: true,
+      supportsVision: true,
+      supportsJson: true,
+      maxOutputTokens: 4096,
+    },
+  },
+  {
+    id: 'gpt-4o-mini',
+    name: 'GPT-4o Mini',
+    provider: 'openai',
+    costPer1kInputTokens: 0.00015,
+    costPer1kOutputTokens: 0.0006,
+    latencyMs: 300,
+    qualityScore: 0.88,
+    capabilities: {
+      contextWindow: 128000,
+      supportsStreaming: true,
+      supportsTools: true,
+      supportsVision: true,
+      supportsJson: true,
+      maxOutputTokens: 16384,
+    },
+  },
+  // OpenRouter (cheaper alternatives)
+  {
+    id: 'deepseek/deepseek-coder',
+    name: 'DeepSeek Coder',
+    provider: 'openrouter',
+    costPer1kInputTokens: 0.00014,
+    costPer1kOutputTokens: 0.00028,
+    latencyMs: 400,
+    qualityScore: 0.82,
+    capabilities: {
+      contextWindow: 64000,
+      supportsStreaming: true,
+      supportsTools: false,
+      supportsVision: false,
+      supportsJson: true,
+      maxOutputTokens: 8192,
+    },
+  },
+  {
+    id: 'mistralai/mixtral-8x7b-instruct',
+    name: 'Mixtral 8x7B',
+    provider: 'openrouter',
+    costPer1kInputTokens: 0.00027,
+    costPer1kOutputTokens: 0.00027,
+    latencyMs: 350,
+    qualityScore: 0.85,
+    capabilities: {
+      contextWindow: 32000,
+      supportsStreaming: true,
+      supportsTools: true,
+      supportsVision: false,
+      supportsJson: true,
+      maxOutputTokens: 4096,
+    },
+  },
+  // Local models (free)
+  {
+    id: 'llama3.2:latest',
+    name: 'Llama 3.2',
+    provider: 'ollama',
+    costPer1kInputTokens: 0,
+    costPer1kOutputTokens: 0,
+    latencyMs: 600,
+    qualityScore: 0.80,
+    capabilities: {
+      contextWindow: 128000,
+      supportsStreaming: true,
+      supportsTools: true,
+      supportsVision: false,
