+      maxOutputTokens: 4096,
+    },
+  },
+  {
+    id: 'phi-4-mini',
+    name: 'Phi-4 Mini (ONNX)',
+    provider: 'onnx',
+    costPer1kInputTokens: 0,
+    costPer1kOutputTokens: 0,
+    latencyMs: 100,
+    qualityScore: 0.75,
+    capabilities: {
+      contextWindow: 8192,
+      supportsStreaming: false,
+      supportsTools: false,
