+      mechanism: 'hyperbolic',
+      consensusOutput,
+      attentionWeights,
+      confidence: this.computeConfidence(attentionWeights),
+      latency: 0,
+      participatingAgents: agentOutputs.map(o => o.agentId),
+      metadata: { curvature, suitableFor: 'hierarchical structures' },
+    };
+  }
