+    const dim = 64;
+    const embedding = new Float32Array(dim);
+
+    for (let i = 0; i < content.length; i++) {
+      const idx = i % dim;
+      embedding[idx] += content.charCodeAt(i) / 1000;
+    }
+
+    // Normalize
+    const norm = Math.sqrt(embedding.reduce((s, v) => s + v * v, 0));
+    if (norm > 0) {
