+  if (!trajectory) {
+    throw new Error(`Trajectory ${input.trajectoryId} not found`);
+  }
+
+  trajectory.context = { ...trajectory.context, ...input.context };
+
+  return {
+    updated: true,
+    contextKeys: Object.keys(trajectory.context),
+  };
